// Normaliza texto e prepara metadados base para os chunks
const workerConfig = $('Set: Configurações do Worker').item.json;
const inputData = $input.item.json;

// Coleta texto de qualquer ramo
let rawText = inputData.text
  || inputData.extracted_text
  || inputData.data
  || '';

if (!rawText || rawText.trim().length < 50) {
  throw new Error(`[${workerConfig.file_name}] Texto extraído muito curto ou vazio: "${rawText.substring(0, 100)}"`);
}

// Normalização
const cleanText = rawText
  .replace(/\r\n/g, '\n')
  .replace(/\r/g, '\n')
  .replace(/\t/g, ' ')
  .replace(/ {3,}/g, '  ')
  .replace(/\n{5,}/g, '\n\n\n')
  .replace(/[^\S\n]+/g, ' ')  // espaços múltiplos (exceto newlines)
  .trim();

const base_metadata = {
  file_key:    workerConfig.file_key,
  file_name:   workerConfig.file_name,
  mime_type:   workerConfig.mime_type,
  etag:        workerConfig.etag,
  source:      'supabase_s3',
  bucket:      workerConfig.bucket_name,
  collection:  'Demo Events Co_cruzeiros',
  ingested_at: new Date().toISOString()
};

console.log(`[NORMALIZAÇÃO] ${workerConfig.file_name}: ${cleanText.length} chars`);

return [{
  json: {
    doc_text:      cleanText,
    char_count:    cleanText.length,
    base_metadata,
    file_key:      workerConfig.file_key,
    file_name:     workerConfig.file_name
  }
}];

// Recursive Character Text Splitter
// chunkSize: 1200 | overlap: 250
const { doc_text, base_metadata, file_key, file_name } = $input.item.json;

const CHUNK_SIZE    = 1200;
const CHUNK_OVERLAP = 250;
const SEPARATORS    = ['\n\n\n', '\n\n', '\n', '. ', '? ', '! ', '; ', ', ', ' ', ''];

function recursiveSplit(text, seps, size, overlap) {
  if (text.length <= size) return [text];

  // Encontra o melhor separador
  let chosenSep = '';
  for (const sep of seps) {
    if (text.includes(sep)) { chosenSep = sep; break; }
  }

  const splits = chosenSep ? text.split(chosenSep) : [text];
  const chunks = [];
  let current = '';

  for (let i = 0; i < splits.length; i++) {
    const piece = splits[i] + (i < splits.length - 1 ? chosenSep : '');

    if ((current + piece).length > size && current.length > 0) {
      if (current.trim().length > 0) chunks.push(current.trim());
      // Overlap: mantém final do chunk anterior
      current = current.length > overlap
        ? current.slice(current.length - overlap) + piece
        : current + piece;
    } else {
      current += piece;
    }
  }
  if (current.trim().length > 0) chunks.push(current.trim());
  return chunks;
}

// Hash simples determinístico (sem crypto)
function strHash(s) {
  let h = 2166136261;
  for (let i = 0; i < Math.min(s.length, 500); i++) {
    h ^= s.charCodeAt(i);
    h = (h * 16777619) >>> 0;
  }
  return h.toString(16);
}

const rawChunks = recursiveSplit(doc_text, SEPARATORS, CHUNK_SIZE, CHUNK_OVERLAP);

const validChunks = rawChunks
  .filter(c => c.length >= 80)  // descarta chunks muito pequenos
  .map((chunk, index) => {
    const hash = strHash(chunk.substring(0, 300));
    const chunk_id = `${file_key}::${index}::${hash}`;
    return {
      chunk_id,
      chunk_text:  chunk,
      chunk_index: index,
      chunk_hash:  hash,
      total_chunks: rawChunks.length,
      metadata: {
        ...base_metadata,
        chunk_index: index,
        chunk_hash:  hash,
        chunk_chars: chunk.length
      }
    };
  });

console.log(`[CHUNKING] ${file_name}: ${validChunks.length} chunks válidos de ${rawChunks.length} brutos`);

return validChunks.map(c => ({ json: c }));

// Combina dados do chunk (batch anterior) com embedding retornado
const chunkData = $('Split In Batches: Loop de Chunks').item.json;
const embResponse = $input.item.json;

const embedding = embResponse?.data?.[0]?.embedding;
if (!embedding || !Array.isArray(embedding) || embedding.length !== 1536) {
  throw new Error(`Embedding inválido para chunk ${chunkData.chunk_id}. Resposta: ${JSON.stringify(embResponse).substring(0, 200)}`);
}

// pgvector aceita formato [0.1, 0.2, ...] como string
const embeddingStr = '[' + embedding.join(',') + ']';

return [{
  json: {
    chunk_id:    chunkData.chunk_id,
    chunk_text:  chunkData.chunk_text,
    metadata:    JSON.stringify(chunkData.metadata),
    embedding:   embeddingStr
  }
}];

// Pega os primeiros 8000 chars do documento para extrair facts
// (o LLM não precisa do doc inteiro para identificar metadados)
const fileData = $('Code: Normalizar Texto').item.json;

const textForExtraction = fileData.doc_text.substring(0, 8000);

return [{
  json: {
    text_sample: textForExtraction,
    file_key: fileData.base_metadata.file_key,
    file_name: fileData.file_name,
    full_length: fileData.doc_text.length
  }
}];

const llmResponse = $input.item.json;
const fileInfo = $('Code: Preparar Texto para Facts').item.json;
// ─── Parse seguro: remove markdown fences antes de parsear ───
let facts = {};
try {
  let content = llmResponse?.text || '{}';

  // Remove ```json ... ``` ou ``` ... ```
  content = content
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();

  facts = JSON.parse(content);
} catch (e) {
  console.error(`[FACTS] Erro ao parsear JSON para ${fileInfo.file_name}:`, e.message);
  facts = { confidence: 0, testimonials: [] };
}

// Hash determinístico
function strHash(s) {
  let h = 2166136261;
  for (let i = 0; i < Math.min(s.length, 300); i++) {
    h ^= s.charCodeAt(i);
    h = (h * 16777619) >>> 0;
  }
  return h.toString(16);
}

const cruzeiro_id = `cruzeiro::${strHash(
  (facts.ship_name  || '') + '::' +
  (facts.start_date || '') + '::' +
  (facts.theme      || '') + '::' +
  fileInfo.file_key
)}`;

const testimonials = Array.isArray(facts.testimonials) ? facts.testimonials : [];
const cruzeiro_data = { ...facts };
delete cruzeiro_data.testimonials;

console.log(`[FACTS] ${fileInfo.file_name}: ship="${facts.ship_name}", confidence=${facts.confidence}, depoimentos=${testimonials.length}`);

return [{
  json: {
    cruzeiro_id,
    cruzeiro_data: {
      ...cruzeiro_data,
      source_file: fileInfo.file_key,
      artist:     Array.isArray(cruzeiro_data.artist)     ? cruzeiro_data.artist     : [],
      highlights: Array.isArray(cruzeiro_data.highlights) ? cruzeiro_data.highlights : [],
      itinerary:  Array.isArray(cruzeiro_data.itinerary)  ? cruzeiro_data.itinerary  : []
    },
    testimonials: testimonials.map((t, i) => ({
      id:          `dep::${strHash(fileInfo.file_key + '::' + i + '::' + (t.quote || ''))}`,
      cruzeiro_id,
      source_file: fileInfo.file_key,
      speaker:     t.speaker   || 'desconhecido',
      role:        t.role      || 'desconhecido',
      sentiment:   t.sentiment || 'neutral',
      key_points:  Array.isArray(t.key_points) ? t.key_points : [],
      quote:       (t.quote || '').substring(0, 500)
    })),
    confidence: facts.confidence || 0,
    file_key:   fileInfo.file_key
  }
}];
